    private static IReadOnlyList<MetadataReference> BuildReferences()
    {
        return
        [
            .. AppDomain
                .CurrentDomain.GetAssemblies()
                .Where(predicate: static a => !a.IsDynamic && !string.IsNullOrEmpty(a.Location))
                .Select(selector: static a => (MetadataReference)MetadataReference.CreateFromFile(a.Location)),
            MetadataReference.CreateFromFile(typeof(SqlObjectMapAttribute).Assembly.Location),
        ];
